def insert(node, char):
    if node is None:
        return {'val': char.lower(), 'left': None, 'right': None}
    if char.lower() < node['val']:
        node['left'] = insert(node['left'], char)
    elif char.lower() > node['val']:
        node['right'] = insert(node['right'], char)
    return node

def process_sequence(seq, index, tree):
    if index >= len(seq):
        return tree
    char = seq[index]
    tree = insert(tree, char)
    return process_sequence(seq, index + 1, tree)

